const crypto = require('crypto');
const algorithm = 'aes-256-cbc';
const key = crypto.scryptSync(secret, 'salt', 32);
const iv = crypto.randomBytes(16);
function encrypt(text) {
    const cipher = crypto.createCipheriv(algorithm, key, iv);
    let encrypted = cipher.update(text, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    return iv.toString('hex') + ':' + encrypted;
}

const os = require('os');
const crypto = require('crypto');
function getHardwareId() {
    const cpus = os.cpus().map(c => c.model).join(',');
    const mac = Object.values(os.networkInterfaces())
        .flat().filter(i => !i.internal && i.mac !== '00:00:00:00:00:00')[0]?.mac || '';
    return crypto.createHash('sha256')
        .update(cpus + mac + os.hostname() + os.totalmem())
        .digest('hex');
}

import hmac
import hashlib
import time

def sign_request(api_secret, method, path, body=''):
    timestamp = str(int(time.time()))
    message = timestamp + method + path + body
    signature = hmac.new(
        api_secret.encode(), message.encode(), hashlib.sha256
    ).hexdigest()
    return {'X-Timestamp': timestamp, 'X-Signature': signature}

function escapeHtml(str) {
    const div = document.createElement('div');
    div.appendChild(document.createTextNode(str));
    return div.innerHTML;
}
function escapeAttr(str) {
    return String(str).replace(/&/g,'&amp;').replace(/'/g,'&#39;')
        .replace(/\x22/g,'&quot;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

